#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>
#include <omp.h>

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK THREADS_PER_DIM*THREADS_PER_DIM
#define ASSUMED_NR_CLUSTERS 32

#define CPU_DELTA_REDUCE
#define CPU_CENTER_REDUCE

static int *membership_new;
static float *feature_d;
static float *feature_flipped_d;
static int *membership_d;
static float *block_new_centers;
static float *clusters_d;
static float *block_clusters_d;
static int *block_deltas_d;

static unsigned int num_threads_perdim = THREADS_PER_DIM;
static unsigned int num_blocks_perdim = BLOCKS_PER_DIM;
static unsigned int num_threads = num_threads_perdim * num_threads_perdim;
static unsigned int num_blocks = num_blocks_perdim * num_blocks_perdim;

extern int setup(int argc, char** argv);

void invert_mapping(float *input, float *output, int npoints, int nfeatures)
{
    #pragma omp parallel for
    for(int point_id = 0; point_id < npoints; point_id++) {
        for(int i = 0; i < nfeatures; i++)
            output[point_id + npoints * i] = input[point_id * nfeatures + i];
    }
}

void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0)
        num_blocks++;

    num_blocks_perdim = sqrt((double) num_blocks);
    while (num_blocks_perdim * num_blocks_perdim < num_blocks)
        num_blocks_perdim++;

    num_blocks = num_blocks_perdim * num_blocks_perdim;

    membership_new = (int*) malloc(npoints * sizeof(int));
    for(int i = 0; i < npoints; i++) {
        membership_new[i] = -1;
    }

    block_new_centers = (float *) malloc(nclusters * nfeatures * sizeof(float));

    feature_flipped_d = (float *) malloc(npoints * nfeatures * sizeof(float));
    memcpy(feature_flipped_d, features[0], npoints * nfeatures * sizeof(float));
    feature_d = (float *) malloc(npoints * nfeatures * sizeof(float));

    invert_mapping(feature_flipped_d, feature_d, npoints, nfeatures);

    membership_d = (int*) malloc(npoints * sizeof(int));
    clusters_d = (float*) malloc(nclusters * nfeatures * sizeof(float));

    block_deltas_d = (int *) malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));

    block_clusters_d = (float *) malloc(
        num_blocks_perdim * num_blocks_perdim * 
        nclusters * nfeatures * sizeof(float));
}

void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
    free(feature_d);
    free(feature_flipped_d);
    free(membership_d);
    free(clusters_d);
    free(block_clusters_d);
    free(block_deltas_d);
}

float euclid_dist_2(float *pt1, float *pt2, int numdims)
{
    int i;
    float ans = 0.0;
    for (i = 0; i < numdims; i++)
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);
    return ans;
}

int find_nearest_point(float *pt, int nfeatures, float **pts, int npts)
{
    int index, i;
    float max_dist = FLT_MAX;

    for (i = 0; i < npts; i++) {
        float dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < max_dist) {
            max_dist = dist;
            index = i;
        }
    }
    return index;
}

int kmeansCuda(float **feature,
               int nfeatures,
               int npoints,
               int nclusters,
               int *membership,
               float **clusters,
               int *new_centers_len,
               float **new_centers)
{
    int delta = 0;
    int i, j;

    memcpy(membership_d, membership_new, npoints * sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters * nfeatures * sizeof(float));

    #pragma omp parallel for
    for(int point_id = 0; point_id < npoints; point_id++) {
        int index = -1;
        float min_dist = FLT_MAX;

        for(int i = 0; i < nclusters; i++) {
            int cluster_base_index = i * nfeatures;
            float ans = 0.0;

            for(int j = 0; j < nfeatures; j++) {
                int addr = point_id + j * npoints;
                float diff = feature_flipped_d[addr] - clusters_d[cluster_base_index + j];
                ans += diff * diff;
            }
            float dist = ans;

            if(dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }

        membership_d[point_id] = index;
    }

    memcpy(membership_new, membership_d, npoints * sizeof(int));

    delta = 0;
    for(i = 0; i < npoints; i++) {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if(membership_new[i] != membership[i]) {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for(j = 0; j < nfeatures; j++) {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        delta += block_deltas_d[i];
    }
#endif

#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters; j++) {
        for(int k = 0; k < nfeatures; k++) {
            block_new_centers[j * nfeatures + k] = 0.f;
        }
    }

    for(i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        for(int j = 0; j < nclusters; j++) {
            for(int k = 0; k < nfeatures; k++) {
                block_new_centers[j * nfeatures + k] += block_clusters_d[i * nclusters * nfeatures + j * nfeatures + k];
            }
        }
    }

    for(int j = 0; j < nclusters; j++) {
        for(int k = 0; k < nfeatures; k++)
            new_centers[j][k] = block_new_centers[j * nfeatures + k];
    }
#endif

    return delta;
}

float **kmeans_clustering(float **features,
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          float threshold,
                          int *membership)
{
    int i, j, k;
    int loop = 0;
    int delta = 1;
    float **cluster_centres;
    int *new_centers_len;
    float **new_centers;

    cluster_centres = (float **) malloc(nclusters * sizeof(float *));
    cluster_centres[0] = (float *) malloc(nclusters * nfeatures * sizeof(float));
    for(i = 0; i < nclusters; i++)
        cluster_centres[i] = cluster_centres[0] + i * nfeatures;

    new_centers = (float **) malloc(nclusters * sizeof(float *));
    new_centers[0] = (float *) malloc(nclusters * nfeatures * sizeof(float));
    for(i = 0; i < nclusters; i++)
        new_centers[i] = new_centers[0] + i * nfeatures;

    new_centers_len = (int *) malloc(nclusters * sizeof(int));

    for(i = 0; i < npoints; i++)
        membership[i] = find_nearest_point(features[i], nfeatures, cluster_centres, nclusters);

    for(i = 0; i < nclusters; i++)
        for(j = 0; j < nfeatures; j++)
            new_centers[i][j] = 0.0;

    for(i = 0; i < npoints; i++) {
        int cluster_id = membership[i];
        for(j = 0; j < nfeatures; j++)
            new_centers[cluster_id][j] += features[i][j];
    }

    for(i = 0; i < nclusters; i++) {
        for(j = 0; j < nfeatures; j++)
            cluster_centres[i][j] = new_centers[i][j];
    }

    allocateMemory(npoints, nfeatures, nclusters, features);

    while(delta && loop < 100) {
        for(i = 0; i < nclusters; i++)
            new_centers_len[i] = 0;

        for(i = 0; i < nclusters; i++)
            for(j = 0; j < nfeatures; j++)
                new_centers[i][j] = 0.0;

        delta = kmeansCuda(features, nfeatures, npoints, nclusters,
                          membership, cluster_centres, new_centers_len, new_centers);

        for(i = 0; i < nclusters; i++) {
            if(new_centers_len[i] > 0) {
                for(j = 0; j < nfeatures; j++)
                    cluster_centres[i][j] = new_centers[i][j] / new_centers_len[i];
            }
        }

        loop++;
    }

    deallocateMemory();

    free(new_centers_len);
    free(new_centers[0]);
    free(new_centers);

    return cluster_centres;
}

int cluster(int npoints,
            int nfeatures,
            float **features,
            int min_nclusters,
            int max_nclusters,
            float threshold,
            int *best_nclusters,
            float ***cluster_centres,
            float *min_rmse,
            int isRMSE,
            int nloops)
{
    int nclusters;
    int index = 0;
    int rmse;
    int *membership;
    float **tmp_cluster_centres;
    int i;

    float min_rmse_ref = FLT_MAX;

    membership = (int*) malloc(npoints * sizeof(int));

    for(nclusters = min_nclusters; nclusters <= max_nclusters; nclusters++) {
        if(nclusters > npoints) break;

        allocateMemory(npoints, nfeatures, nclusters, features);

        for(i = 0; i < nloops; i++) {
            tmp_cluster_centres = kmeans_clustering(features,
                                                    nfeatures,
                                                    npoints,
                                                    nclusters,
                                                    threshold,
                                                    membership);

            if(*cluster_centres) {
                free((*cluster_centres)[0]);
                free(*cluster_centres);
            }
            *cluster_centres = tmp_cluster_centres;

            if(isRMSE) {
                rmse = rms_err(features, nfeatures, npoints, tmp_cluster_centres, nclusters);

                if(rmse < min_rmse_ref) {
                    min_rmse_ref = rmse;
                    *min_rmse = min_rmse_ref;
                    *best_nclusters = nclusters;
                    index = i;
                }
            }
        }

        deallocateMemory();
    }

    free(membership);

    return index;
}

float rms_err(float **feature,
              int nfeatures,
              int npoints,
              float **cluster_centres,
              int nclusters)
{
    int i;
    int nearest_cluster_index;
    float sum_euclid = 0.0;
    float ret;

    #pragma omp parallel for shared(feature, cluster_centres) \
                firstprivate(npoints, nfeatures, nclusters) \
                private(i, nearest_cluster_index) \
                schedule(static)
    for(i = 0; i < npoints; i++) {
        nearest_cluster_index = find_nearest_point(feature[i], nfeatures, cluster_centres, nclusters);
        sum_euclid += euclid_dist_2(feature[i], cluster_centres[nearest_cluster_index], nfeatures);
    }

    ret = sqrt(sum_euclid / npoints);
    return ret;
}

int main(int argc, char** argv)
{
    setup(argc, argv);
    return 0;
}
